@using sv_8a8ce216cdd0440e80d57613fb34abd8.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ───── Left Sidebar: Channel List ───── *@
    <aside class="chat-sidebar">
        <h4 class="sidebar-title">Channels</h4>

        @if (channels is null)
        {
            <p class="sidebar-loading">Loading…</p>
        }
        else
        {
            <ul class="channel-list">
                @foreach (var ch in channels)
                {
                    <li class="channel-item @(ch.Id == activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch)">
                        <div class="channel-header-row">
                            <span class="channel-name"># @ch.Name</span>
                            @if (ch.UnreadCount > 0)
                            {
                                <span class="unread-badge">@ch.UnreadCount</span>
                            }
                        </div>
                        @if (!string.IsNullOrWhiteSpace(ch.Description))
                        {
                            <span class="channel-desc">@Truncate(ch.Description, 60)</span>
                        }
                    </li>
                }
            </ul>
        }
    </aside>

    @* ───── Main Message Area ───── *@
    <section class="chat-main @(threadOpen ? "" : "chat-main--wide")">
        @if (activeChannel is not null)
        {
            <header class="main-header">
                <h5 class="main-channel-name"># @activeChannel.Name</h5>
                <span class="main-channel-desc">@activeChannel.Description</span>
            </header>

            <div class="message-list" @ref="messageListRef" @onscroll="OnMessageListScrollAsync">
                @if (loadingMore)
                {
                    <div class="loading-more">Loading older messages…</div>
                }
                @if (messages is not null)
                {
                    @foreach (var msg in messages)
                    {
                        <div class="message-card" @onmouseover="() => hoveredMessageId = msg.Id"
                             @onmouseout="() => { if (hoveredMessageId == msg.Id) hoveredMessageId = null; }">
                            <div class="message-meta">
                                <span class="message-author">@msg.Author</span>
                                <span class="message-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-content">@msg.Content</div>

                            @* Reactions *@
                            @if (msg.Reactions?.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => AddReactionAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @* Thread starter link *@
                            @if (threadSummaries.TryGetValue(msg.Id, out var ts))
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                    @ts.ReplyCount @(ts.ReplyCount == 1 ? "reply" : "replies")
                                    — last @FormatRelativeTime(ts.LastReplyAt)
                                </button>
                            }

                            @* Hover action buttons *@
                            @if (hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg.Id)">💬 Reply</button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" title="Add reaction"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                                        @if (emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in commonEmojis)
                                                {
                                                    <button class="emoji-btn"
                                                            @onclick="() => AddReactionAsync(msg.Id, emoji)">@emoji</button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            @* Message input *@
            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Type a message…"
                          @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="OnMainKeyDownAsync"></textarea>
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(newMessageText)"
                        @onclick="SendMainMessageAsync">Send</button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ───── Right Panel: Thread View ───── *@
    @if (threadOpen)
    {
        <aside class="chat-thread-panel">
            <header class="thread-header">
                <h5>Thread</h5>
                <button class="thread-close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </header>

            @if (threadRootMessage is not null)
            {
                <div class="thread-root-quote">
                    <span class="message-author">@threadRootMessage.Author</span>
                    <span class="message-time">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                    <p class="message-content">@threadRootMessage.Content</p>
                </div>
            }

            <div class="thread-reply-list">
                @if (threadReplies is not null)
                {
                    @foreach (var reply in threadReplies)
                    {
                        <div class="message-card">
                            <div class="message-meta">
                                <span class="message-author">@reply.Author</span>
                                <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Reply in thread…"
                          @bind="threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDownAsync"></textarea>
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(threadReplyText)"
                        @onclick="SendThreadReplyAsync">Reply</button>
            </div>
        </aside>
    }
</div>

@code {
    // ── Data ──
    private List<Channel>? channels;
    private int activeChannelId;
    private Channel? activeChannel;
    private List<Message>? messages;
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    // ── Pagination ──
    private const int PageSize = 30;
    private int loadedCount;
    private bool loadingMore;
    private bool allLoaded;

    // ── UI state ──
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private string newMessageText = string.Empty;
    private ElementReference messageListRef;

    // ── Thread state ──
    private bool threadOpen;
    private int? threadRootId;
    private Message? threadRootMessage;
    private List<Message>? threadReplies;
    private string threadReplyText = string.Empty;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels?.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    // ── Channel selection ──

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannelId = channel.Id;
        activeChannel = channel;
        loadedCount = 0;
        allLoaded = false;
        messages = new();

        await LoadMessagesAsync();
        _ = ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();

        await ScrollToBottomAsync();
    }

    private async Task LoadMessagesAsync()
    {
        var batch = await ChatService.GetMessagesAsync(activeChannelId, loadedCount, PageSize);
        if (batch.Count < PageSize)
        {
            allLoaded = true;
        }

        // Newer messages are appended; older batches are prepended
        if (loadedCount == 0)
        {
            messages = batch;
        }
        else
        {
            messages!.InsertRange(0, batch);
        }

        loadedCount += batch.Count;
        BuildThreadSummaries();
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        if (messages is null) return;

        // Group replies by their root message
        var replies = messages.Where(m => m.ReplyToId.HasValue).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }

    // ── Scroll pagination ──

    private async Task OnMessageListScrollAsync()
    {
        if (allLoaded || loadingMore) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            loadingMore = true;
            StateHasChanged();

            await LoadMessagesAsync();

            loadingMore = false;
        }
    }

    // ── Send message ──

    private async Task SendMainMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText)) return;

        var sent = await ChatService.SendMessageAsync(activeChannelId, newMessageText.Trim(), null);
        newMessageText = string.Empty;
        messages?.Add(sent);
        BuildThreadSummaries();

        await ScrollToBottomAsync();
    }

    private async Task OnMainKeyDownAsync(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMainMessageAsync();
        }
    }

    // ── Reactions ──

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh messages to pick up the updated reaction state
        var refreshed = await ChatService.GetMessagesAsync(activeChannelId, 0, loadedCount);
        messages = refreshed;
        BuildThreadSummaries();
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    // ── Thread ──

    private async Task OpenThreadAsync(int rootMessageId)
    {
        threadRootId = rootMessageId;
        threadRootMessage = messages?.FirstOrDefault(m => m.Id == rootMessageId);
        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        threadReplyText = string.Empty;
        threadOpen = true;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootId = null;
        threadRootMessage = null;
        threadReplies = null;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootId is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannelId, threadReplyText.Trim(), threadRootId);
        threadReplyText = string.Empty;
        threadReplies?.Add(reply);

        // Also add to main message list so thread summary updates
        messages?.Add(reply);
        BuildThreadSummaries();
    }

    private async Task OnThreadKeyDownAsync(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Helpers ──

    private async Task ScrollToBottomAsync()
    {
        await Task.Yield();
        await JS.InvokeVoidAsync("eval",
            "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string Truncate(string text, int maxLen) =>
        text.Length <= maxLen ? text : text[..(maxLen - 1)] + "…";
}
"}

