namespace sv_8a8ce216cdd0440e80d57613fb34abd8.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

/* ═══════════════════════════════════════════
   Chat Layout — three-panel responsive design
   ═══════════════════════════════════════════ */

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    background: #1a1d21;
    color: #d1d2d3;
}

/* ── Sidebar ── */

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    background: #19171d;
    border-right: 1px solid #2c2d30;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-title {
    padding: 16px 16px 8px;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    letter-spacing: 0.3px;
}

.sidebar-loading {
    padding: 16px;
    color: #9a9b9e;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 4px 8px;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 12px;
    border-radius: 6px;
    cursor: pointer;
    margin-bottom: 2px;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #27242c;
}

.channel-item.active {
    background: #1164a3;
    color: #fff;
}

.channel-header-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-desc {
    display: block;
    font-size: 0.75rem;
    color: #9a9b9e;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-desc {
    color: #c5d5e4;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    border-radius: 10px;
    padding: 1px 7px;
    min-width: 20px;
    text-align: center;
    flex-shrink: 0;
}

/* ── Main area ── */

.chat-main {
    width: 55%;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    background: #1a1d21;
    transition: width 0.2s ease;
}

.chat-main--wide {
    width: 80%;
}

.main-header {
    padding: 12px 20px;
    border-bottom: 1px solid #2c2d30;
    flex-shrink: 0;
}

.main-channel-name {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 700;
    color: #fff;
}

.main-channel-desc {
    font-size: 0.8rem;
    color: #9a9b9e;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #9a9b9e;
    font-size: 1rem;
}

/* ── Message list ── */

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

.loading-more {
    text-align: center;
    padding: 8px;
    color: #9a9b9e;
    font-size: 0.8rem;
}

.message-card {
    position: relative;
    padding: 8px 12px;
    border-radius: 6px;
    margin-bottom: 4px;
    transition: background 0.1s;
}

.message-card:hover {
    background: #222529;
}

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #fff;
}

.message-time {
    font-size: 0.75rem;
    color: #9a9b9e;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

/* Reactions */

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    background: #2c2d30;
    border: 1px solid #3e3f42;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    color: #d1d2d3;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #3e3f42;
}

/* Thread link */

.thread-link {
    background: none;
    border: none;
    color: #1d9bd1;
    font-size: 0.78rem;
    padding: 2px 0;
    cursor: pointer;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

/* Hover actions */

.message-actions {
    position: absolute;
    top: 4px;
